INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Cross-file and cross-function analysis$q$, $q$Traces data flow across multiple files and functions to catch complex, multi-step vulnerabilities that single-file pattern matching would miss.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Semgrep Code (SAST)$q$, $q$Over 20,000 Pro rules maintained by Semgrep's security research team, plus community rules from the public Semgrep Registry.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Semgrep Supply Chain (SCA)$q$, $q$Reachability-based dependency scanning that flags only vulnerable open-source packages actually called by application code.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Semgrep Secrets$q$, $q$Detects hardcoded credentials and API keys with validation checks to reduce false positives.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$AI-powered triage and autofix$q$, $q$Uses an AI-credit allowance to suggest fixes and auto-triage findings, cutting down manual review time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$CI/CD and IDE integrations$q$, $q$Plugs into GitHub, GitLab, Jenkins, and editors like VS Code to run scans automatically in pull requests or pre-commit hooks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Code-like custom rule authoring$q$, $q$Custom rules are written in a syntax that resembles the target source code rather than a complex AST query language.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Flexible deployment for Enterprise$q$, $q$Self-hosted, cloud, or hybrid deployment with support for on-premise source-code management systems.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Free and open-source core scanner with a genuinely usable free tier for small teams$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Fast, lightweight scanning that fits naturally into CI/CD pipelines$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Custom rules use familiar code-like syntax instead of a complex query language$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Reachability analysis in Supply Chain reduces alert fatigue from irrelevant dependency CVEs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Broad language coverage across 30-plus languages suits polyglot codebases$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Team and Enterprise pricing is per-contributor, which can get expensive for large engineering organizations$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Secrets detection is a separate paid add-on rather than bundled into the base Team plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Enterprise pricing is custom and opaque, requiring a sales conversation for larger deployments$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Some advanced Pro rules and cross-file analysis depth are limited on the free tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Like most SAST tools, tuning is needed to minimize false positives on large legacy codebases$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$What is Semgrep used for?$q$, $q$Semgrep is used for static application security testing, scanning source code to find bugs, security vulnerabilities, vulnerable dependencies, and hardcoded secrets before code reaches production.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Is Semgrep free?$q$, $q$Yes, Semgrep has a free Community edition covering up to 10 repositories and 10 contributors with Code and Supply Chain scanning included. Larger teams need the paid Team or Enterprise plans.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$What is the difference between Semgrep Code, Supply Chain, and Secrets?$q$, $q$Semgrep Code is the SAST engine for finding bugs and vulnerabilities in first-party code, Supply Chain is software composition analysis for open-source dependency risk, and Secrets detects hardcoded credentials and API keys.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$How much does Semgrep Team cost?$q$, $q$The Team plan starts at $30 per contributor per month for up to 500 private repositories, with the Secrets product available as a $15 per month add-on.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$What programming languages does Semgrep support?$q$, $q$Semgrep supports more than 30 languages, with Python, JavaScript, TypeScript, Java, Go, C, C++, Ruby, PHP, Rust, C#, and Kotlin at general availability.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Who founded Semgrep and when?$q$, $q$Semgrep was founded in 2017 and is headquartered in San Francisco, California.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Can Semgrep be self-hosted?$q$, $q$Yes, Enterprise customers can deploy Semgrep in the cloud, self-hosted, or in a hybrid model, including support for on-premise source-code management systems.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Does Semgrep integrate with CI/CD pipelines?$q$, $q$Yes, Semgrep integrates with GitHub, GitLab, Jenkins, and IDEs such as VS Code so scans can run automatically on pull requests or before commits.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$DevSecOps pipeline scanning$q$, $q$Security and platform engineering teams embed Semgrep directly into CI/CD pipelines to catch vulnerabilities and secrets before merge.$q$, $q$DevSecOps and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Custom internal rule authoring$q$, $q$Security engineers write custom Semgrep rules to enforce internal framework or API usage patterns unique to their codebase.$q$, $q$Application security engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Open-source and pre-commit scanning$q$, $q$Individual developers and open-source maintainers run the free Semgrep scanner locally or as a pre-commit hook to catch issues early.$q$, $q$Open-source maintainers and individual developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Free (Community)$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to 10 repositories","Up to 10 contributors","60 AI credits included","Semgrep Code and Supply Chain products included","Cross-file analysis with Pro rules"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Team$q$, $q$$30 per contributor per month$q$, $q$Monthly, per contributor$q$, NULL, $q$["Up to 500 private repositories","Choice of Code (SAST) or Supply Chain (SCA); Secrets available for $15 per month","20 AI credits per developer per month","Single sign-on (SSO) with OIDC and SAML","REST API access","Distributed scans enabled"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Unlimited repositories and contributors","50 AI credits per developer per month","On-premise source code management support","Custom CI/CD integrations","Dedicated account manager","Custom AI model provider support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Semgrep is a static application security testing tool built to find bugs, vulnerabilities, and hardcoded secrets directly inside source code before it reaches production. Founded in 2017 and headquartered in San Francisco, the company built Semgrep around a simple idea: security rules should look like the code they are scanning, so developers, not just security specialists, can write and maintain them.$q$, $q$The platform now spans three connected products, Semgrep Code for SAST, Semgrep Supply Chain for dependency risk, and Semgrep Secrets for credential leaks, all sharing a single scanning engine, rule registry, and dashboard so security and engineering teams can manage findings from one place.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Semgrep's core differentiator is cross-file and cross-function analysis that traces how data flows through an application, which lets it catch multi-step vulnerabilities that simple single-file pattern matching would miss. It ships with more than 20,000 Pro rules curated by Semgrep's research team, on top of a public rule registry contributed to by the open-source community.$q$, $q$Semgrep Supply Chain applies reachability analysis to open-source dependency scanning, surfacing only the vulnerable packages that are actually invoked by application code, which meaningfully cuts down on the alert fatigue common with traditional CVE scanners. AI-powered triage and autofix features, gated behind a per-plan AI-credit allowance, help teams prioritize and resolve findings faster.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7b87aa12-a696-4762-9cbd-1a738f0fd2c7', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Semgrep offers a free Community edition covering up to 10 repositories and 10 contributors with both Code and Supply Chain included. The Team plan starts at $30 per contributor per month for up to 500 private repositories, with the Secrets product available as a $15 per month add-on.$q$, $q$Enterprise pricing is custom and scales with the number of developers, deployment model (cloud, self-hosted, or hybrid), and required features, and typically involves a direct sales conversation for large or regulated organizations that need on-premise source-code management support.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Keyword Magic Tool$q$, $q$Keyword research database covering billions of keywords across 142-plus country-level databases.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Site Audit$q$, $q$Technical SEO health checks flagging crawlability, indexability, and Core Web Vitals issues.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Position Tracking$q$, $q$Daily rank tracking by location and device for target keyword sets.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Backlink Analytics and Audit$q$, $q$Link profile analysis and toxic-link identification to protect domain authority.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$On Page SEO Checker and SEO Writing Assistant$q$, $q$Content optimization recommendations based on top-ranking competitor pages.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Advertising Research and PPC Keyword Tool$q$, $q$Competitor ad spend and paid search intelligence for PPC campaign planning.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Content Marketing and Social Media toolkits$q$, $q$Content ideation, scheduling, and performance tracking across marketing channels.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$AI-driven generative engine optimization$q$, $q$Tools for tracking brand visibility and mentions inside AI-generated search and chat answers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Comprehensive suite covering SEO, PPC, content, and social in one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Large keyword and competitor database spanning 142-plus country markets$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Frequent feature updates, including newer AI and generative engine optimization tracking$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Strong educational resources through Semrush Academy$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Public company with established financial stability and long operating history$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Expensive relative to single-purpose SEO tools, especially at Guru and Business tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Steep learning curve for beginners given the sheer number of bundled tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Project and keyword tracking limits scale with plan tier, requiring upgrades for larger sites$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Some historical and international data requires higher-tier plans$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Credit or limit-based systems on certain tools can add unexpected costs for heavy users$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$What is Semrush used for?$q$, $q$Semrush is used for SEO keyword research, technical site audits, rank tracking, backlink analysis, PPC competitor research, and broader digital marketing tasks like content and social media planning.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$How much does Semrush cost?$q$, $q$Semrush's core plans start at $139.95 per month for Pro, $249.95 per month for Guru, and $499.95 per month for Business, with lower rates available on annual billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Is Semrush publicly traded?$q$, $q$Yes, Semrush is a publicly traded company on the New York Stock Exchange under the ticker symbol SEMR.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Does Semrush offer a free trial?$q$, $q$Semrush commonly offers limited free trials or a restricted free account for basic lookups, though full functionality requires a paid subscription.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$What languages does the Semrush interface support?$q$, $q$The Semrush interface is available in English, Spanish, German, French, Italian, Portuguese, Turkish, Vietnamese, Chinese, and Japanese.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Where is Semrush headquartered?$q$, $q$Semrush is headquartered in Boston, Massachusetts, with additional offices including locations in Pennsylvania, Texas, and the Czech Republic.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Does Semrush have an API?$q$, $q$Yes, API access is available, primarily on the higher-tier Business plan.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$What are the main alternatives to Semrush?$q$, $q$Common alternatives include Ahrefs, Moz Pro, and Ubersuggest, each offering overlapping but differently scoped SEO and marketing research tools.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$In-house SEO and PPC management$q$, $q$Marketing teams use Semrush to research keywords, audit site health, and analyze competitor paid search campaigns from a single dashboard.$q$, $q$In-house marketing and SEO teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Agency client reporting$q$, $q$SEO and digital marketing agencies use Semrush to manage multiple client projects, track rankings, and generate reports.$q$, $q$Digital marketing and SEO agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Content strategy and research$q$, $q$Content teams use the Keyword Magic Tool and SEO Writing Assistant to plan and optimize articles for organic search.$q$, $q$Content marketers and writers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Pro$q$, $q$$139.95 per month ($117.33 per month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["5 projects","500 keywords tracked","10,000 results per report","Core SEO, PPC, and content tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Guru$q$, $q$$249.95 per month ($208.33 per month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["15 projects","1,500 keywords tracked","Historical data access","Content Marketing toolkit and Looker Studio integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$Business$q$, $q$$499.95 per month ($416.66 per month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["40 projects","5,000 keywords tracked","API access","Extended reporting limits and Share of Voice tool"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Semrush was founded in 2008 and is headquartered in Boston, Massachusetts. The company went public and now trades on the New York Stock Exchange under the ticker SEMR, employing more than 1,500 people worldwide and serving over 1.8 million marketing professionals across 142 countries.$q$, $q$Originally built around keyword research, Semrush has expanded into a full digital marketing suite of 55-plus tools covering SEO, PPC, content marketing, social media, local search, and AI search visibility, positioning itself as a single platform for most organic and paid marketing workflows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Semrush's core SEO toolkit includes the Keyword Magic Tool for keyword research, Site Audit for technical SEO health checks including Core Web Vitals, Position Tracking for rank monitoring by location and device, and Backlink Analytics for link-profile and toxic-link analysis.$q$, $q$Beyond core SEO, the platform includes Advertising Research and a PPC Keyword Tool for competitor ad intelligence, a Content Marketing toolkit and SEO Writing Assistant for optimizing content, a social media scheduling tool, and newer generative engine optimization features that track how brands appear in AI-generated answers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3564d834-f51a-4718-9030-849e68652d1f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Semrush offers three primary self-serve subscription tiers: Pro at $139.95 per month, Guru at $249.95 per month, and Business at $499.95 per month, each with a discount of roughly 15 to 17 percent when billed annually.$q$, $q$Higher tiers unlock more projects, more tracked keywords, historical data, API access, and extended reporting limits, and Semrush also sells a separate Semrush One bundle with its own Starter, Pro+, and Advanced pricing tiers starting around $199 per month.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Free-forever plan$q$, $q$Covers up to 2,500 subscribers and 15,000 emails per month with nearly all core features unlocked.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Drag-and-drop email builder$q$, $q$Pre-built templates and a visual editor for building campaigns without coding.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Marketing automation workflows$q$, $q$Automation sequences and autoresponders triggered by subscriber behavior.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Transactional and triggered emails$q$, $q$Sent via SMTP or API for receipts, confirmations, and event-based messages.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$SMS marketing$q$, $q$Send SMS campaigns alongside email from the same platform and dashboard.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Pop-ups and signup forms$q$, $q$Tools for growing subscriber lists directly on a website.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Audience segmentation and reporting$q$, $q$Segment contacts and review basic campaign analytics and performance reports.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Pay-as-you-go credits$q$, $q$Purchase sending credits as needed with no recurring monthly commitment.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Generous free-forever plan with nearly all features unlocked$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Affordable entry-level paid pricing compared to larger ESPs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Combines email and SMS marketing in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Unlimited seats and campaigns included on paid plans$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Simple and beginner-friendly interface$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Fewer advanced integrations than larger ESPs such as Mailchimp or Klaviyo$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Smaller third-party app ecosystem overall$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Deliverability reputation is less established than legacy providers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Reporting and analytics are more basic than enterprise-grade tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Support responsiveness can vary depending on plan tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Is Sender really free?$q$, $q$Yes, Sender offers a free-forever plan covering up to 2,500 subscribers and 15,000 emails per month with most core features included, not just a limited trial.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$How much does Sender cost after the free plan?$q$, $q$Paid plans start around $7 per month for the Standard tier and about $14 per month for the Professional tier, with pricing scaling based on subscriber list size.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Where is Sender headquartered?$q$, $q$Sender is headquartered in Vilnius, Lithuania, and was founded in 2012.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Does Sender support SMS marketing?$q$, $q$Yes, Sender lets users send SMS campaigns alongside email marketing from the same dashboard.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Is Sender good for ecommerce businesses?$q$, $q$Sender is commonly used by small ecommerce brands due to its automation features, transactional email support, and affordable pricing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Does Sender offer a pay-as-you-go option?$q$, $q$Yes, Sender offers a pay-as-you-go credit plan for businesses that prefer not to commit to a recurring monthly subscription.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Is Sender venture funded?$q$, $q$No, Sender is a bootstrapped company that has grown without outside venture capital funding.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Small ecommerce email marketing$q$, $q$Small online stores use Sender's automation and transactional email features to send order confirmations and marketing campaigns affordably.$q$, $q$Small ecommerce store owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Newsletter publishing$q$, $q$Solo creators and bloggers use Sender's free plan to grow and email a subscriber list without upfront cost.$q$, $q$Independent creators and newsletter writers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Combined email and SMS outreach$q$, $q$Small businesses use Sender to run coordinated email and SMS campaigns from a single platform.$q$, $q$Small business owners and marketers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Free$q$, $q$$0 per month$q$, $q$Monthly$q$, NULL, $q$["Up to 2,500 subscribers","15,000 emails per month","Automation, transactional emails, and unlimited campaigns included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Standard$q$, $q$From $7 per month$q$, $q$Monthly, scales with list size$q$, NULL, $q$["Unlimited campaigns and automation","3 role-based seats","Pop-ups and signup forms"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Professional$q$, $q$From $14 per month$q$, $q$Monthly, scales with list size$q$, NULL, $q$["Advanced automation","Priority support","10 seats"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$Pay as you go$q$, $q$Credit-based, no recurring fee$q$, $q$One-time credit purchase$q$, NULL, $q$["Buy sending credits as needed","No monthly commitment","Full feature access"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Sender is a bootstrapped email and SMS marketing platform founded in 2012 and headquartered in Vilnius, Lithuania. The company has grown without outside venture funding and employs roughly 30 people, positioning itself as an affordable, feature-rich alternative to larger email service providers.$q$, $q$Sender targets small businesses, solo creators, and ecommerce brands, with its free-forever plan and low-cost paid tiers designed to unlock most core functionality, including automation and transactional email, without requiring an upgrade for basic use cases.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Sender combines a drag-and-drop email builder, marketing automation workflows, transactional and triggered emails via SMTP or API, and SMS marketing within a single dashboard, letting small teams manage multiple channels without separate tools.$q$, $q$Additional features include pop-ups and signup forms for list growth, audience segmentation, basic analytics and reporting, and a pay-as-you-go credit option for businesses that prefer not to commit to a recurring subscription.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('12459a1a-3818-4e4e-89a8-720e89fe4675', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Sender's free-forever plan covers up to 2,500 subscribers and 15,000 emails per month with nearly all core features unlocked, which is more generous than many competing free tiers.$q$, $q$Paid plans start around $7 per month for the Standard tier and about $14 per month for the Professional tier, both scaling with subscriber list size, with unlimited seats and campaigns included, and a pay-as-you-go credit option available as an alternative to a recurring subscription.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Email API$q$, $q$RESTful and SMTP integration for sending transactional email from applications.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Marketing Campaigns$q$, $q$Newsletter design, automation, and audience segmentation tools for marketing email.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Dynamic templates$q$, $q$Drag-and-drop and code-based editors for building reusable email templates.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Email validation API$q$, $q$Validates addresses before sending to reduce bounce rates and protect sender reputation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Deliverability tooling$q$, $q$Dedicated IPs, IP warmup schedules, and domain authentication (SPF, DKIM, DMARC) support.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Real-time analytics and webhooks$q$, $q$Tracks opens, clicks, and bounces with event webhooks for downstream processing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Twilio ecosystem integration$q$, $q$Combine email with SMS, voice, and other Twilio communication channels in unified workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$High-volume infrastructure$q$, $q$Built to reliably deliver tens of billions of emails per month across its customer base.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Highly scalable and reliable for high-volume transactional email$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Robust, well-documented developer API$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Strong deliverability infrastructure including dedicated IPs and domain authentication$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Part of the broader Twilio communications platform for combined channel workflows$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Free tier available for testing and low-volume use$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Pricing can escalate quickly at high sending volumes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Marketing automation features are less advanced than dedicated ESPs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Support quality can vary depending on plan tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Interface is considered less polished than some newer competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Separate pricing for Email API versus Marketing Campaigns can be confusing to compare$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Is SendGrid the same as Twilio?$q$, $q$SendGrid was acquired by Twilio in 2019 and now operates as Twilio SendGrid, a product line within the broader Twilio communications platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$How much does SendGrid cost?$q$, $q$The Email API has paid plans generally starting around $19.95 per month, while Marketing Campaigns paid plans start at $15 per month, both scaling with volume.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Does SendGrid have a free plan?$q$, $q$Yes, there is a limited free trial tier sending up to 100 emails per day for the Email API, and a free Marketing Campaigns tier covering up to 2,000 contacts.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$What is SendGrid mainly used for?$q$, $q$SendGrid is primarily used for transactional email such as password resets and receipts, as well as marketing newsletters through its separate Marketing Campaigns product.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$When was SendGrid founded?$q$, $q$SendGrid was founded in 2009 in Denver, Colorado by Isaac Saldana, Jose Lopez, and Tim Jenkins.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Does SendGrid support dedicated IP addresses?$q$, $q$Yes, dedicated IPs are available on higher-tier Email API plans to help manage sender reputation.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Can SendGrid integrate with other Twilio products?$q$, $q$Yes, because it is part of Twilio, SendGrid can be combined with Twilio's SMS, voice, and other communication APIs in unified workflows.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Transactional email for applications$q$, $q$Developers use SendGrid's Email API to send receipts, password resets, and account notifications reliably at scale.$q$, $q$Software developers and SaaS engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$High-volume API-based delivery$q$, $q$Companies with large user bases rely on SendGrid for dependable, high-throughput transactional email infrastructure.$q$, $q$SaaS companies and platform businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Marketing newsletters via Twilio SendGrid$q$, $q$Marketing teams use Marketing Campaigns to design and send newsletters alongside their transactional email setup.$q$, $q$Marketing teams at companies already using Twilio infrastructure$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Email API Free$q$, $q$$0$q$, $q$Trial$q$, NULL, $q$["Up to 100 emails per day"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Email API Essentials$q$, $q$$19.95 to $29.95 per month$q$, $q$Monthly$q$, NULL, $q$["No daily send limit","Email support","Optional dedicated IP add-on"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Email API Pro$q$, $q$$89.95 to $949.95 per month$q$, $q$Monthly$q$, NULL, $q$["Dedicated IPs included","Sub-user management","Higher sending throughput"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Marketing Campaigns Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["Up to 2,000 contacts","6,000 emails per month"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$Marketing Campaigns paid$q$, $q$From $15 per month$q$, $q$Monthly$q$, NULL, $q$["Larger contact lists","Automation workflows","Advanced segmentation"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$SendGrid was founded in 2009 in Denver, Colorado, and grew into a major transactional email provider before Twilio acquired it in 2019 for approximately 2 billion dollars. It now operates as Twilio SendGrid, part of the publicly traded Twilio communications platform headquartered in San Francisco.$q$, $q$The platform is split into two product lines: the developer-focused Email API for transactional email, and Marketing Campaigns for newsletters and promotional email, each with its own pricing structure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SendGrid's Email API supports RESTful and SMTP integration, dynamic templates with drag-and-drop and code editors, an email validation API to reduce bounces, and deliverability tools including dedicated IPs, IP warmup, and domain authentication.$q$, $q$Marketing Campaigns adds newsletter design, automation, and segmentation tools, while real-time analytics and event webhooks give visibility into opens, clicks, and bounces across both product lines, and integration with the broader Twilio ecosystem allows combined email, SMS, and voice workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d6c91d2-4c18-4368-83f2-7ea2115662de', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The Email API offers a limited free trial of up to 100 emails per day, with paid Essentials plans around $19.95 to $29.95 per month and Pro plans from $89.95 to $949.95 per month depending on volume and dedicated IP needs.$q$, $q$Marketing Campaigns has a separate free tier for up to 2,000 contacts and 6,000 emails per month, with paid plans starting at $15 per month and scaling with list size and automation requirements.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Multi-platform scheduling$q$, $q$Schedule posts across Facebook, Instagram, LinkedIn, TikTok, X, YouTube, Google Business Profile, Threads, and Bluesky.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Bulk content importer$q$, $q$Import and schedule a month's worth of content in one batch operation.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Smart Queues$q$, $q$Automatically recycle evergreen content on a recurring schedule without manual re-posting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Unified social inbox$q$, $q$Manage comments, direct messages, and mentions across platforms from one inbox.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Built-in image editor and integrations$q$, $q$Edit visuals directly, with connections to GIPHY, Pexels, and Canva for content creation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$White-label reporting$q$, $q$Automated, brandable performance reports designed for agencies presenting results to clients.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Content approval workflows$q$, $q$Team and client collaboration tools for reviewing and approving posts before publishing.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Post customization by platform$q$, $q$Tailor posts per network with profile tags, locations, and hashtags.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Strong agency-focused features like white-label reports and client approval workflows$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Wide platform coverage including newer networks like Threads and Bluesky$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Bulk scheduling saves time for high-volume posting schedules$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Unified inbox simplifies engagement management across platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Long operating history as a bootstrapped, independently run company$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Pricing rises steeply at higher tiers, reaching up to roughly 891 dollars per month for Enterprise$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Interface can feel less modern compared to some newer competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Some advanced analytics are gated behind higher-tier plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Occasional platform API sync delays reported by users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Per-profile limits require plan upgrades as social accounts grow$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$What is Sendible used for?$q$, $q$Sendible is used for scheduling, publishing, monitoring, and reporting on social media content across multiple platforms, primarily by agencies and marketing teams.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Is Sendible an email marketing tool?$q$, $q$No, Sendible is a social media management and scheduling platform, not an email marketing tool, despite its name resembling other 'Send' branded products.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$How much does Sendible cost?$q$, $q$Sendible's pricing starts at $29 per month for the Creator plan and scales up to $750 to $891 per month for the Enterprise plan, depending on user and profile counts.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Which social platforms does Sendible support?$q$, $q$Sendible supports Facebook, Instagram, LinkedIn, TikTok, X, YouTube, Google Business Profile, Threads, and Bluesky.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Who owns Sendible?$q$, $q$Sendible was acquired by Traject in March 2021 and continues to operate under the Sendible brand.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Is Sendible good for agencies?$q$, $q$Yes, Sendible includes agency-specific features such as white-label reporting and client approval workflows.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Where is Sendible headquartered?$q$, $q$Sendible is headquartered in London, United Kingdom, and was founded in 2008.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Agency client management$q$, $q$Social media agencies use Sendible to manage scheduling, reporting, and approvals across many client accounts from one dashboard.$q$, $q$Social media management agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Multi-platform content scheduling$q$, $q$Marketing teams use Sendible's bulk importer and Smart Queues to plan content across many social networks at once.$q$, $q$In-house marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Freelance social media management$q$, $q$Freelancers use the entry-level Creator plan to manage a handful of client social profiles affordably.$q$, $q$Freelance social media managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Creator$q$, $q$$29 per month$q$, $q$Monthly$q$, NULL, $q$["1 user","6 social profiles"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Traction$q$, $q$$89 per month$q$, $q$Monthly$q$, NULL, $q$["Additional users and profiles","Expanded reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Advanced$q$, $q$$299 to $524 per month$q$, $q$Monthly$q$, NULL, $q$["Team collaboration","Content approval workflows"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Enterprise$q$, $q$$750 to $891 per month$q$, $q$Monthly$q$, NULL, $q$["Largest profile and user allowances","White-label reporting"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Sendible is a social media management platform founded in 2008 and headquartered in London, United Kingdom. The company is bootstrapped, employs an estimated 50 to 100 people, and was acquired by Traject in March 2021 while continuing to operate under its own brand.$q$, $q$The platform is built primarily for agencies and marketing teams managing multiple client social accounts, offering scheduling, publishing, monitoring, and reporting across a wide range of social networks from a single dashboard.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Sendible supports scheduling across Facebook, Instagram, LinkedIn, TikTok, X, YouTube, Google Business Profile, Threads, and Bluesky, with a bulk content importer, Smart Queues for recycling evergreen content, and a unified social inbox for comments, DMs, and mentions.$q$, $q$Agency-oriented features include a built-in image editor with Canva, GIPHY, and Pexels integration, white-label and automated performance reports, and content approval workflows supporting team and client collaboration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Sendible's pricing starts at $29 per month for the Creator plan, covering one user and six social profiles, and moves up to $89 per month for Traction with additional users and profiles.$q$, $q$Larger teams pay $299 to $524 per month for the Advanced tier, and agencies needing the highest profile and user counts along with white-label reporting pay $750 to $891 per month for Enterprise.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Battle-tested SMTP mail routing$q$, $q$Decades of production use handling core SMTP mail transfer and routing on the internet.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Rule-based configuration via sendmail.cf$q$, $q$Highly configurable mail routing and address rewriting through a mature, if complex, configuration language.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Open-source distribution$q$, $q$Maintained by Proofpoint as a free, community-available open-source project.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Sentrion commercial platform$q$, $q$Proofpoint's commercial enterprise email infrastructure platform built on Sendmail technology.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Broad Unix and Linux compatibility$q$, $q$Historically shipped with many BSD and Unix-derived operating systems.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Milter support$q$, $q$Extensive third-party mail filter (milter) integrations for spam and virus scanning.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Multi-domain relay routing$q$, $q$Supports complex multi-domain, multi-relay enterprise mail routing scenarios.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Mature documentation base$q$, $q$Decades of accumulated documentation and community knowledge from its long operating history.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Extremely mature and battle-tested, powering internet mail since the early 1980s$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Free and open source with an actively maintained community distribution$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Highly configurable for complex, non-standard mail routing needs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Large historical body of documentation and community knowledge$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Backed by Proofpoint's enterprise support for commercial Sentrion deployments$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$The sendmail.cf configuration syntax is notoriously difficult to learn$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Largely superseded in new deployments by Postfix and Exim$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Smaller active community than modern MTA alternatives$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Fewer modern built-in security features compared to newer mail servers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Market share has declined sharply since its 1990s peak of around 80 percent$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$What is Sendmail?$q$, $q$Sendmail is one of the oldest mail transfer agents (MTA) on the internet, originally created in the early 1980s at UC Berkeley to route SMTP email between servers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Is Sendmail still maintained?$q$, $q$Yes, the open-source Sendmail project continues to receive periodic maintenance releases under Proofpoint's stewardship as of 2026.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Who owns Sendmail now?$q$, $q$Sendmail, Inc. was acquired by Proofpoint in October 2013, and Proofpoint was later taken private by Thoma Bravo in 2021.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Is Sendmail free?$q$, $q$The core Sendmail distribution is free and open source; Proofpoint's Sentrion-based commercial platform and enterprise support are separately priced.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$How does Sendmail compare to Postfix and Exim?$q$, $q$Sendmail is older and more established but has a harder-to-learn configuration syntax, and has lost significant market share to Postfix and Exim in new deployments since the mid-2000s.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$How old is Sendmail?$q$, $q$Sendmail originated in the early 1980s, first shipping with BSD 4.1c in 1983, making it roughly four decades old as of 2026.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Legacy enterprise mail infrastructure$q$, $q$Enterprise IT teams maintain existing Sendmail deployments that have routed mail reliably for years or decades.$q$, $q$Enterprise system administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Highly configurable Unix mail routing$q$, $q$System administrators use Sendmail when complex, custom mail routing rules are needed that benefit from its mature configuration language.$q$, $q$Unix and Linux system administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Enterprise email infrastructure via Sentrion$q$, $q$Large organizations use Proofpoint's Sentrion platform, built on Sendmail technology, for enterprise-grade email routing and support.$q$, $q$Enterprise IT and security teams using Proofpoint$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Open Source$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Community-maintained MTA","Self-support via documentation and community","Free to download and deploy"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$Sentrion / Enterprise (Proofpoint)$q$, $q$Custom pricing$q$, $q$Custom, contact Proofpoint$q$, NULL, $q$["Commercial support and SLAs","Enterprise mail routing features","Dedicated account management"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Sendmail originated in the early 1980s at UC Berkeley as a derivative of an earlier program called delivermail, and shipped with BSD 4.1c in 1983 as one of the first mail servers to support TCP/IP email delivery. It dominated internet mail routing through the 1990s before losing significant market share to Postfix and Exim in the 2000s.$q$, $q$The commercial company behind it, Sendmail, Inc., was founded in 1999 by creator Eric Allman and was acquired by Proofpoint in October 2013 for about 23 million dollars. Proofpoint, now headquartered in Sunnyvale, California, was itself taken private by Thoma Bravo in 2021 and continues to maintain both the open-source Sendmail project and a commercial Sentrion-based offering.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Sendmail is a highly configurable, battle-tested MTA that handles SMTP mail routing, address rewriting, and complex multi-domain relay scenarios through its sendmail.cf configuration language, refined over more than 40 years of production use.$q$, $q$It supports extensive third-party milter integrations for spam and virus filtering, and its commercial Sentrion platform builds enterprise features such as dedicated support and advanced routing controls on top of the open-source core.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The open-source Sendmail distribution is free to download and self-support, maintained by Proofpoint for the community.$q$, $q$Organizations needing dedicated support or the Sentrion-based enterprise platform must contact Proofpoint directly for custom commercial pricing, as no public list pricing is available for the enterprise offering.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4741d451-b4f1-4455-802f-b4d98dfdba96', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Email marketing automation$q$, $q$Drag-and-drop email builder combined with automation flows for triggered and scheduled campaigns.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$SMS and web push notifications$q$, $q$Send SMS campaigns and browser web push notifications alongside email.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Chatbot builder$q$, $q$Build chatbots for WhatsApp, Instagram, Telegram, and Facebook Messenger without coding.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Free built-in CRM$q$, $q$Manage sales pipelines and customer deals directly within the marketing platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Landing page and website builder$q$, $q$Drag-and-drop builder with templates for creating landing pages and simple websites.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Multi-channel automation workflows$q$, $q$Chain email, SMS, and chatbot triggers together based on subscriber behavior.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Transactional email sending$q$, $q$Send transactional emails via SMTP or API integration.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Online course and LMS builder$q$, $q$Build and sell online courses and digital content through a built-in learning management system.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Combines email, SMS, chat, and push notifications in a single platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Generous free tier that includes CRM access$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Competitive pay-as-you-go pricing for email sending$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Chatbot builder for WhatsApp, Instagram, and Telegram differentiates it from typical ESPs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Bundled landing page and course-builder tools add extra value beyond messaging$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Breadth of bundled features can mean less depth than specialized single-channel tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Deliverability reputation reports are mixed compared to more established ESPs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Customer support response times can vary by plan tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Interface can feel cluttered given the number of bundled products$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Some advanced automation features are gated behind higher-tier paid plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Is SendPulse free to use?$q$, $q$Yes, SendPulse offers a free plan covering up to 15,000 emails per month along with basic CRM and automation features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$What channels does SendPulse support?$q$, $q$SendPulse supports email, SMS, web push notifications, and chatbots for WhatsApp, Instagram, Telegram, and Facebook Messenger.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$How much does SendPulse cost?$q$, $q$Paid Standard plans start around $9.85 per month and scale with subscriber count, with a pay-as-you-go option starting at roughly 32 dollars for 10,000 emails.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Does SendPulse include a CRM?$q$, $q$Yes, SendPulse includes a free built-in CRM for managing sales pipelines and customer deals.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Where is SendPulse headquartered?$q$, $q$SendPulse is headquartered in New York, with additional offices in Ukraine, Brazil, and Mexico.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$When was SendPulse founded?$q$, $q$SendPulse was founded in 2015.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Can SendPulse build chatbots?$q$, $q$Yes, SendPulse includes a chatbot builder supporting WhatsApp, Instagram, Telegram, and Facebook Messenger.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Does SendPulse offer a course-building tool?$q$, $q$Yes, SendPulse includes an online course and learning management system builder for selling digital content.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Multi-channel small business marketing$q$, $q$Small businesses use SendPulse to run email, SMS, and chatbot campaigns from one platform instead of multiple separate tools.$q$, $q$Small business owners and marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Ecommerce chat-based engagement$q$, $q$Ecommerce brands use SendPulse's WhatsApp and Telegram chatbots to engage customers alongside traditional email campaigns.$q$, $q$Ecommerce brands and online retailers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Course creation and marketing$q$, $q$Course creators use SendPulse's LMS builder together with its email and automation tools to build and sell online courses.$q$, $q$Online course creators and educators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Free$q$, $q$$0 per month$q$, $q$Monthly$q$, NULL, $q$["Up to 15,000 emails per month","Basic CRM and automation access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Standard$q$, $q$From $9.85 per month$q$, $q$Monthly, scales with subscriber count$q$, NULL, $q$["Full email automation","Landing page builder access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Pro$q$, $q$Higher tier pricing based on subscriber count$q$, $q$Monthly$q$, NULL, $q$["Advanced automation","A/B testing","Higher sending limits"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Pay as you go$q$, $q$From $32 for 10,000 emails$q$, $q$One-time credit purchase$q$, NULL, $q$["No monthly commitment","Pay only for emails sent"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$Enterprise / VIP$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["For subscriber lists over 1 million","Dedicated account support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$SendPulse is a multi-channel marketing automation platform founded in 2015, headquartered in New York, with additional offices in Ukraine, Brazil, and Mexico supporting its globally distributed team of roughly 159 employees.$q$, $q$The platform has grown to around 3 million registered users as of mid-2025 by bundling email, SMS, web push, and chatbot messaging alongside a free CRM, landing page builder, and course and LMS tools into a single subscription.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core channels include email marketing with a drag-and-drop builder, SMS marketing, web push notifications, and chatbot builders for WhatsApp, Instagram, Telegram, and Facebook Messenger, all manageable from one dashboard.$q$, $q$Additional tools include a free built-in CRM for pipeline and deal management, a landing page and website builder, multi-step automation that chains email, SMS, and chatbot triggers together, and an online course and LMS builder for selling digital content.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d598c49-9a29-4abb-82c3-8560ce7dd623', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SendPulse's free plan covers up to 15,000 emails per month with basic CRM and automation access, while paid Standard plans start around $9.85 per month and scale with subscriber count.$q$, $q$A pay-as-you-go option starts at roughly 32 dollars for 10,000 emails for businesses avoiding a recurring subscription, and a custom-priced VIP or Enterprise tier is available for lists exceeding one million subscribers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$One-time license fee$q$, $q$A single $69 payment unlocks the software with no recurring monthly subscription cost.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Self-hosted deployment$q$, $q$Runs on your own PHP and MySQL or MariaDB server for full data ownership and control.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Amazon SES sending$q$, $q$Sends bulk campaigns through Amazon SES at roughly $1 per 10,000 emails.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Drag-and-drop email builder$q$, $q$Create campaigns visually without writing code.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Subscriber list management$q$, $q$Manage lists with custom fields and audience segments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Campaign analytics$q$, $q$Track opens, clicks, bounces, and unsubscribes for each campaign.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Autoresponders$q$, $q$Basic automation workflows for triggered follow-up emails.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$API access$q$, $q$Integrate external signup forms and applications with Sendy's subscriber lists.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Dramatically lower sending costs than SaaS email platforms thanks to Amazon SES pricing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$One-time license fee avoids ongoing subscription costs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Full control and ownership of data since the application is self-hosted$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Lightweight PHP and MySQL stack runs on standard shared or VPS hosting$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Unlimited subscribers, campaigns, and emails once the license is purchased$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Requires self-hosting and basic server maintenance skills$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Deliverability and Amazon SES reputation management is the user's own responsibility$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Fewer built-in integrations than mainstream SaaS email service providers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Interface and templates are more basic than modern hosted competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Support relies on documentation and community forums rather than a dedicated support team$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$What is Sendy?$q$, $q$Sendy is a self-hosted email newsletter application that runs on your own server and sends bulk email through Amazon SES.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$How much does Sendy cost?$q$, $q$Sendy uses a one-time license fee of $69 per site, rather than a recurring monthly subscription.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Does Sendy require Amazon SES?$q$, $q$Yes, Sendy is built to send campaigns through Amazon SES, which typically costs about $1 per 10,000 emails sent.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Is Sendy self-hosted?$q$, $q$Yes, Sendy must be installed on your own PHP and MySQL or MariaDB web server rather than being used as a hosted SaaS product.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Is Sendy good for large newsletters?$q$, $q$Yes, Sendy is popular with publishers and bloggers sending large newsletters because Amazon SES sending costs are much lower than typical subscription-based email platforms.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Does Sendy have an API?$q$, $q$Yes, Sendy provides an API for integrating external signup forms and applications with its subscriber lists.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Who maintains Sendy?$q$, $q$Sendy is maintained by a small independent development team; detailed public information about company size, founding date, and headquarters is not published.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$High-volume newsletter publishing$q$, $q$Bloggers and publishers with large subscriber lists use Sendy to cut recurring sending costs via Amazon SES.$q$, $q$Budget-conscious bloggers and newsletter publishers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Developer-controlled email infrastructure$q$, $q$Developers and agencies use Sendy for full control over their email sending stack instead of relying on a third-party SaaS provider.$q$, $q$Developers and technical agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Cost-sensitive bulk sending$q$, $q$Businesses with very large lists use Sendy to minimize per-email sending costs compared to subscription-based ESPs.$q$, $q$Businesses with large subscriber lists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Single Site License$q$, $q$$69 one-time payment$q$, $q$One-time$q$, NULL, $q$["Unlimited campaigns and subscribers on one installation","Self-hosted on your own server","No recurring subscription fee"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$Amazon SES usage$q$, $q$Approximately $1 per 10,000 emails$q$, $q$Pay-as-you-go$q$, NULL, $q$["Usage-based email sending cost","Billed directly through Amazon Web Services"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Sendy is a self-hosted email newsletter application built on PHP and MySQL or MariaDB, designed to run on standard web hosting rather than as a hosted SaaS product. Its defining feature is a one-time license fee rather than a recurring monthly subscription.$q$, $q$Sendy sends campaigns through Amazon SES, which allows for bulk email delivery at roughly $1 per 10,000 emails, making it especially popular with publishers and developers who send high volumes of newsletters and want to minimize ongoing sending costs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include a drag-and-drop email builder, subscriber list management with custom fields and segments, campaign analytics covering opens, clicks, bounces, and unsubscribes, and basic autoresponder and automation workflows.$q$, $q$An API is available for integrating external signup forms and applications directly with Sendy's subscriber lists, and because the software is self-hosted, users retain full control and ownership over their subscriber data and sending infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44d9699e-8d32-4e15-b625-c6a58b71f09e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Sendy is sold as a single-site license for a one-time payment of $69, which unlocks unlimited campaigns and subscribers on that installation with no recurring subscription fee.$q$, $q$Ongoing costs are limited to Amazon SES usage, priced at roughly $1 per 10,000 emails sent, plus whatever web hosting the user already pays for to run the self-hosted application.$q$]::text[], 2);
