-- Enrichment marathon batch: Semgrep, Semrush, Sender, SendGrid, Sendible, Sendmail, SendPulse, Sendy

-- ── Semgrep ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Semgrep is a fast, open-source static application security testing (SAST) tool that scans source code for bugs, vulnerabilities, and secrets using lightweight, pattern-based rules across 30-plus programming languages.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (free open-source scanner plus paid Team and Enterprise tiers)$q$, pricing_model),
  starting_price = COALESCE($q$Free for up to 10 repositories and 10 contributors; paid Team plan starts at $30 per contributor per month$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$Approximately 200 to 250 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Semgrep Review 2026: Pricing, Features, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Semgrep costs in 2026, how its static analysis engine works, and whether the Free, Team, or Enterprise plan fits your AppSec workflow.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Semgrep is an open-source static application security testing (SAST) tool created by the company Semgrep (formerly r2c), which was founded in 2017 and is headquartered in San Francisco, California. Semgrep scans source code for bugs, security vulnerabilities, and code quality issues using rules that are written in a syntax resembling the target programming language itself, rather than a complex abstract-syntax-tree query language, which makes custom rule authoring accessible to developers who are not security specialists. The platform supports more than 30 programming languages at varying maturity levels, with Python, JavaScript, TypeScript, Java, Go, C and C++, Ruby, PHP, Rust, C#, and Kotlin generally available. Semgrep is distributed as three product lines: Semgrep Code for static analysis with cross-file and cross-function data-flow tracing and access to more than 20,000 Pro rules maintained by Semgrep's security research team; Semgrep Supply Chain for software composition analysis that uses reachability analysis to flag only the vulnerable open-source dependencies actually called by application code, reducing noise from irrelevant CVEs; and Semgrep Secrets for detecting hardcoded credentials and API keys with validation checks. The product also includes AI-assisted triage and autofix suggestions, consumed through an AI-credit allowance that scales by plan. Pricing follows three tiers. The Free (Community) edition costs nothing and covers up to 10 repositories, up to 10 contributors, 60 AI credits, and both the Code and Supply Chain products with cross-file analysis using Pro rules. The Team plan starts at $30 per contributor per month, covering up to 500 private repositories, a choice of one core product (with the Secrets add-on priced separately at $15 per month), 20 AI credits per developer per month, single sign-on via OIDC and SAML, REST API access, and distributed scanning. The Enterprise tier uses custom, volume-based pricing and adds unlimited repositories and contributors, 50 AI credits per developer per month, support for on-premise source-code management systems, custom CI/CD integrations, a dedicated account manager, and custom AI model provider support. Semgrep integrates directly into developer workflows through GitHub, GitLab, Jenkins, and IDE plugins such as VS Code, allowing scans to run automatically in pull requests or pre-commit hooks. It competes with tools such as Snyk, CodeQL, SonarQube, and Checkmarx in the DevSecOps and application security space, and is commonly adopted by engineering and security teams that want fast, low-noise static analysis embedded directly into CI/CD pipelines rather than a separate, slow security review stage.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7b87aa12-a696-4762-9cbd-1a738f0fd2c7';

