-- ── Semrush ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Semrush is an all-in-one digital marketing platform offering keyword research, technical site audits, competitor analysis, backlink tracking, PPC research, content marketing, and AI-driven search visibility tools used by over 1.8 million marketers worldwide.$q$, short_description),
  pricing_model = COALESCE($q$Tiered subscription, billed monthly or annually$q$, pricing_model),
  starting_price = COALESCE($q$$139.95 per month for the Pro plan billed monthly, or about $117.33 per month billed annually$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$1,500-plus employees; publicly traded on the NYSE under the ticker SEMR$q$, company_size),
  headquarters = COALESCE($q$Boston, Massachusetts, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$German$q$, $q$French$q$, $q$Italian$q$, $q$Portuguese$q$, $q$Turkish$q$, $q$Vietnamese$q$, $q$Chinese$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$Semrush Review 2026: Pricing, Features, and Plans Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$Compare Semrush pricing plans, core SEO and PPC features, and company background in 2026 to decide if the platform fits your marketing stack.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Semrush is a publicly traded, all-in-one digital marketing platform founded in 2008 and headquartered in Boston, Massachusetts, with additional offices in Pennsylvania, Texas, and the Czech Republic. Trading on the New York Stock Exchange under the ticker SEMR, the company employs more than 1,500 people and reports annual revenue exceeding $330 million, serving over 1.8 million marketing professionals across 142 countries, including a large share of Fortune 500 companies. What began as a single SEO keyword tool has grown into a suite of 55-plus individual tools spanning organic search, paid advertising, content marketing, social media management, local SEO, competitive intelligence, and newer AI-driven generative engine optimization (GEO) features that track brand visibility inside AI chat and answer engines. Core capabilities include the Keyword Magic Tool for keyword research across a database covering billions of keywords in 142-plus country-level databases, Site Audit for technical SEO health checks covering crawlability, indexability, and Core Web Vitals, Position Tracking for daily rank monitoring by location and device, Backlink Analytics and Backlink Audit for link-profile analysis and toxic-link identification, On Page SEO Checker and SEO Writing Assistant for content optimization, and Advertising Research and PPC Keyword Tool for competitor ad-spend and paid-search intelligence. Semrush's interface is localized into ten languages, including English, Spanish, German, French, Italian, Portuguese, Turkish, Vietnamese, Chinese, and Japanese, reflecting its global user base. Pricing is structured in three core self-serve tiers: Pro at $139.95 per month (about $117.33 per month billed annually) aimed at freelancers and small teams with 5 projects and 500 tracked keywords; Guru at $249.95 per month (about $208.33 annually) adding historical data, the content marketing toolkit, and Looker Studio integration with 15 projects and 1,500 tracked keywords; and Business at $499.95 per month (about $416.66 annually) adding API access and extended limits across 40 projects and 5,000 tracked keywords. Semrush also offers a separate Semrush One bundle starting around $199 per month with Starter, Pro+, and Advanced tiers. The platform competes directly with Ahrefs, Moz, and Ubersuggest in the SEO tooling category, and its scope has expanded well beyond SEO into a broader marketing operations suite, making it one of the most recognizable brands in search marketing software.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3564d834-f51a-4718-9030-849e68652d1f';

