-- ── Sendmail ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Sendmail is one of the oldest mail transfer agents (MTA) on the internet, originally created at UC Berkeley in the early 1980s, now maintained as an open-source project and Sentrion-based commercial offering under Proofpoint.$q$, short_description),
  pricing_model = COALESCE($q$Free open-source MTA, with commercial Sentrion-based support and enterprise features available through Proofpoint$q$, pricing_model),
  starting_price = COALESCE($q$Free as an open-source distribution; commercial and enterprise pricing available on request from Proofpoint$q$, starting_price),
  founded_year = COALESCE(1981, founded_year),
  company_size = COALESCE($q$Sendmail, Inc. was a small company acquired for about 23 million dollars in 2013; it now operates under Proofpoint, which has approximately 5,000 employees$q$, company_size),
  headquarters = COALESCE($q$Originally Emeryville, California; now maintained under Proofpoint, headquartered in Sunnyvale, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Sendmail Guide 2026: History, Current Status, and Proofpoint Ownership$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn Sendmail's origin as a pioneering open-source mail transfer agent, its Proofpoint ownership, and current commercial and open-source options.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Sendmail is one of the earliest mail transfer agents (MTA) on the internet, originally written as a derivative of an earlier program called delivermail by Eric Allman at the University of California, Berkeley, and first shipped with the BSD 4.1c operating system in 1983, making it one of the very first mail servers to support TCP/IP-based email delivery. Sendmail became the dominant mail server software of the early internet era, with an estimated 80 percent of publicly reachable mail servers running it in 1996, though its market share declined sharply from the mid-2000s onward as competitors Postfix and Exim gained adoption, with Exim in particular capturing much of the web hosting market through its bundling with cPanel. The commercial entity behind the software, Sendmail, Inc., was founded in 1999 by Eric Allman and was based in Emeryville, California, later building a commercial product line called Sentrion for enterprise email infrastructure on top of the open-source core. In October 2013, Sendmail, Inc. was acquired by Proofpoint, Inc. for approximately 23 million dollars in cash, and Proofpoint has since maintained both the free open-source Sendmail distribution for the community and a commercial Sentrion-based offering for enterprise customers needing dedicated support. Proofpoint itself was later taken private in 2021 when it was acquired by the private equity firm Thoma Bravo for approximately 12.3 billion dollars, and today Proofpoint is headquartered in Sunnyvale, California with roughly 5,000 employees globally. As of 2026, the open-source Sendmail project continues to receive periodic maintenance releases, with recent versions such as 8.18.2 signed under current-year signing keys, indicating the codebase remains actively maintained rather than abandoned, even though its real-world usage share has fallen to a small fraction of internet mail servers compared to its 1990s peak. Sendmail's configuration is defined through the notoriously complex sendmail.cf syntax, which offers extremely fine-grained control over mail routing, address rewriting, and multi-domain relay scenarios, but is widely regarded as harder to learn than the configuration approaches used by Postfix or Exim. Sendmail supports extensive third-party milter (mail filter) integrations for spam and virus scanning, and remains present in some long-running enterprise and legacy Unix environments where it was deployed decades ago and has not been migrated away from since.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4741d451-b4f1-4455-802f-b4d98dfdba96';

