-- ── Sendy ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Sendy is a self-hosted email newsletter application that runs on your own server and sends bulk campaigns through Amazon SES, offering a one-time license fee instead of a recurring monthly subscription.$q$, short_description),
  pricing_model = COALESCE($q$One-time license purchase for self-hosted software, with no recurring subscription fee$q$, pricing_model),
  starting_price = COALESCE($q$$69 one-time payment for a single-site license$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Sendy Review 2026: One-Time Pricing and Amazon SES Setup$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Sendy's self-hosted, one-time-fee email newsletter software works with Amazon SES, including pricing and core features in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Sendy is a self-hosted email newsletter application that a small independent development team built to run on standard PHP and MySQL or MariaDB web hosting, distinguishing itself from mainstream email service providers through a one-time license fee model rather than a recurring monthly subscription. Instead of paying a per-subscriber monthly fee to a SaaS provider, Sendy customers pay a single one-time license fee of $69 to install and run the software on their own server, giving them full ownership of their sending infrastructure and subscriber data. Sendy sends campaigns through Amazon Simple Email Service (Amazon SES), Amazon's cloud-based transactional and bulk email delivery service, which allows Sendy users to send bulk email at a cost of roughly $1 per 10,000 emails, a small fraction of what typical subscription-based email marketing platforms charge for equivalent sending volume. This combination of a one-time software fee plus extremely low-cost Amazon SES sending is Sendy's core value proposition and has made it a popular choice among publishers, bloggers, and developers who send large newsletters regularly and want to minimize ongoing costs. Core features include a drag-and-drop email builder for creating campaigns without writing code, subscriber list management with support for custom fields and audience segments, campaign analytics that track opens, clicks, bounces, and unsubscribes, basic autoresponder and automation workflows, and an API that lets developers integrate external signup forms and applications directly with Sendy's subscriber lists. Because Sendy is self-hosted, users are responsible for installing and maintaining the application on their own server, configuring their own Amazon SES account and sending domain, and managing their own sender reputation and deliverability, which requires more technical comfort than a typical SaaS email tool but also removes the platform's control over sending limits, subscriber caps, or price increases over time. Publicly available sources do not provide a clearly verifiable founding year, headquarters location, or company size for Sendy, and unlike most SaaS competitors, Sendy does not publish detailed corporate information, consistent with its positioning as a lightweight, developer-oriented software product rather than a large marketing organization; prospective buyers evaluating it should weigh its low fixed cost and full data ownership against the added responsibility of self-hosting, maintaining server security and updates, and managing SES deliverability without a dedicated support team.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '44d9699e-8d32-4e15-b625-c6a58b71f09e';

